sys_script_include.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
var taskerDocumentScripts = Class.create();
taskerDocumentScripts.prototype = {
	initialize: function() {
	},


	getAttachmentAndDocumentSettings: function(gr){
		var taskerDocumentSettings = {};
		taskerDocumentSettings.sNOWAttachmentsOn = false;
		taskerDocumentSettings.docIntDocumentsOn = false;
		taskerDocumentSettings.sharingAttachments = false;
		taskerDocumentSettings.sharingDocuments = false;

		if (gr.sys_id != -1){
			var useAttachmentsorDocuments = gs.getProperty("x_153465_discovert.UseAttachmentsorDocuments");
			taskerDocumentSettings.sNOWAttachmentsOn = (useAttachmentsorDocuments.startsWith("1") || useAttachmentsorDocuments.startsWith("3"));
			taskerDocumentSettings.docIntDocumentsOn = (useAttachmentsorDocuments.startsWith("2") || useAttachmentsorDocuments.startsWith("3"));

			var tableName = gr.getRecordClassName();
			// if the glide record is a Task Instance, get the Shared Settings from the top task
			if (tableName == "x_153465_discovert_route_task_instance"){
				taskerDocumentSettings.sharingAttachments = (gr.u_top_task.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_top_task.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			if (tableName == "x_153465_discovert_task_tree"){
				taskerDocumentSettings.sharingAttachments = (gr.u_task_ref.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_task_ref.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// if the glide record is a Process Template, get the Shared Settings from the Process Template
			if (tableName == "x_153465_discovert_discover_routing_template"){
				taskerDocumentSettings.sharingAttachments = (gr.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// if the glide record is a Process Template Task, get the Shared Settings from the Process Template Task's - Process Template
			if (tableName == "x_153465_discovert_route_tasks"){
				taskerDocumentSettings.sharingAttachments = (gr.tasker_process_definition.u_shared_attachments  == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.tasker_process_definition.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// RJ - PSD - STRY0064692 - first try to save documents to the Shared Documents folder for the Task Tree.
			if (tableName == "x_153465_discovert_suggested_taskers"){
				// just return value of sNOWAttachmentsOn for Suggested Taskers
				taskerDocumentSettings.sharingAttachments = taskerDocumentSettings.sNOWAttachmentsOn == true;
				// just return value of docIntDocumentsOn for Suggested Taskers
				taskerDocumentSettings.sharingDocuments = taskerDocumentSettings.docIntDocumentsOn == true;
			}
			// RJ first try to save documents to the Shared Documents folder for the Task Tree.
			if (tableName == "x_153465_discovert_discover_routing_runtime"){
				// just return value of sNOWAttachmentsOn for Suggested Taskers
				taskerDocumentSettings.sharingAttachments = taskerDocumentSettings.sNOWAttachmentsOn == true;
				// just return value of docIntDocumentsOn for Suggested Taskers
				taskerDocumentSettings.sharingDocuments = taskerDocumentSettings.docIntDocumentsOn == true;
			}

		}
		return taskerDocumentSettings;
	},

		type: 'taskerDocumentScripts'
	};
